def fibonacci(n):
    """Return the nth Fibonacci number using matrix exponentiation."""
    if n < 0:
        raise ValueError("n must be non-negative")
    if n == 0:
        return 0
    if n == 1:
        return 1

    def matrix_mult(A, B):
        return [
            [A[0][0] * B[0][0] + A[0][1] * B[1][0],
             A[0][0] * B[0][1] + A[0][1] * B[1][1]],
            [A[1][0] * B[0][0] + A[1][1] * B[1][0],
             A[1][0] * B[0][1] + A[1][1] * B[1][1]]
        ]

    def matrix_pow(M, p):
        result = [[1, 0], [0, 1]]  # identity
        base = M
        while p > 0:
            if p % 2 == 1:
                result = matrix_mult(result, base)
            base = matrix_mult(base, base)
            p //= 2
        return result

    F = [[1, 1], [1, 0]]
    result = matrix_pow(F, n)
    return result[0][1]

def fibonacci(n):
    cache = {}
    def fib(k):
        if k in cache:
            return cache[k]
        if k <= 0:
            return 0
        if k == 1:
            return 1
        if k == 2:
            return 1
        if k % 2 == 0:
            m = k // 2
            fm = fib(m)
            fm1 = fib(m - 1)
            result = fm * (2 * fm1 + fm)
        else:
            m = (k + 1) // 2
            fm = fib(m)
            fm1 = fib(m - 1)
            result = fm * fm + fm1 * fm1
        cache[k] = result
        return result
    return fib(n)

