def fibonacci(n):
    """Fast doubling method for Fibonacci numbers."""
    if n < 0:
        raise ValueError("Negative argument")

    def _fib(k):
        if k == 0:
            return (0, 1)
        a, b = _fib(k >> 1)
        c = a * (2 * b - a)
        d = a * a + b * b
        if k & 1:
            return (d, c + d)
        else:
            return (c, d)

    return _fib(n)[0]

def fibonacci(n):
    if n == 0:
        return 0
    if n == 1:
        return 1
    memo = [0] * (n + 1)
    memo[0] = 0
    memo[1] = 1
    for i in range(2, n + 1):
        memo[i] = memo[i - 1] + memo[i - 2]
    return memo[n]
